namespace sv_80ece8c648014ec1825afb6301f0bffd.Services;

public record Product(int Id, string Name, decimal Price, string Category, double Rating, bool InStock, string ImageUrl);
public record ProductFilter(List<string>? Categories, decimal? MinPrice, decimal? MaxPrice, bool InStockOnly);
public record PagedResult<T>(List<T> Items, int TotalCount, int Page, int PageSize);

public interface IProductService
{
    Task<PagedResult<Product>> SearchAsync(ProductFilter filter, string sortBy, int page, int pageSize);
    Task<List<string>> GetCategoriesAsync();
}

@page "/catalog"
@using sv_80ece8c648014ec1825afb6301f0bffd.Services
@inject IProductService ProductService
@rendermode InteractiveServer

<PageTitle>Product Catalog</PageTitle>

<h1 class="mb-4">Product Catalog</h1>

<div class="row">
    @* ── Left Sidebar: Filters ── *@
    <div class="col-md-3">
        <div class="card">
            <div class="card-header fw-bold">Filters</div>
            <div class="card-body">
                @* Category checkboxes *@
                <h6>Category</h6>
                @if (_categories is not null)
                {
                    @foreach (var category in _categories)
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="checkbox" id="@($"cat-{category}")"
                                   checked="@(_selectedCategories.Contains(category))"
                                   @onchange="e => ToggleCategory(category, (bool)e.Value!)" />
                            <label class="form-check-label" for="@($"cat-{category}")">@category</label>
                        </div>
                    }
                }

                <hr />

                @* Price range *@
                <h6>Price Range</h6>
                <div class="mb-2">
                    <label class="form-label" for="minPrice">Min Price</label>
                    <input id="minPrice" type="number" class="form-control form-control-sm"
                           min="0" step="0.01" @bind="_minPrice" />
                </div>
                <div class="mb-2">
                    <label class="form-label" for="maxPrice">Max Price</label>
                    <input id="maxPrice" type="number" class="form-control form-control-sm"
                           min="0" step="0.01" @bind="_maxPrice" />
                </div>

                <hr />

                @* In-stock toggle *@
                <div class="form-check mb-3">
                    <input class="form-check-input" type="checkbox" id="inStockOnly" @bind="_inStockOnly" />
                    <label class="form-check-label" for="inStockOnly">In Stock Only</label>
                </div>

                @* Action buttons *@
                <button class="btn btn-primary w-100 mb-2" @onclick="ApplyFilters">Apply Filters</button>
                <button class="btn btn-outline-secondary w-100" @onclick="ClearFilters">Clear Filters</button>
            </div>
        </div>
    </div>

    @* ── Main Content Area ── *@
    <div class="col-md-9">
        @if (_error is not null)
        {
            <div class="alert alert-danger" role="alert">
                <strong>Error:</strong> @_error
            </div>
        }
        else if (_isLoading)
        {
            <div class="d-flex justify-content-center align-items-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
                <span class="ms-3">Loading products…</span>
            </div>
        }
        else if (_result is null || _result.Items.Count == 0)
        {
            <div class="alert alert-info" role="alert">
                No products found. Try adjusting your filters.
            </div>
        }
        else
        {
            @* Toolbar *@
            <div class="d-flex justify-content-between align-items-center mb-3">
                <div>
                    <label class="form-label me-2 mb-0" for="sortBy">Sort by:</label>
                    <select id="sortBy" class="form-select form-select-sm d-inline-block w-auto"
                            @onchange="OnSortChanged">
                        @foreach (var option in _sortOptions)
                        {
                            <option value="@option.Value" selected="@(option.Value == _sortBy)">@option.Label</option>
                        }
                    </select>
                </div>
                <span class="text-muted">
                    Showing @((_result.Page - 1) * _result.PageSize + 1)–@(Math.Min(_result.Page * _result.PageSize, _result.TotalCount))
                    of @_result.TotalCount products
                </span>
            </div>

            @* Product Grid *@
            <div class="row row-cols-1 row-cols-sm-2 row-cols-lg-3 g-4">
                @foreach (var product in _result.Items)
                {
                    <div class="col">
                        <div class="card h-100 product-card" @onclick="() => OnProductSelected.InvokeAsync(product.Id)" style="cursor:pointer;">
                            @* Placeholder image *@
                            <div class="card-img-top bg-light d-flex align-items-center justify-content-center"
                                 style="height:180px;" role="img" aria-label="@product.Name">
                                <span class="text-muted">@product.Name</span>
                            </div>
                            <div class="card-body d-flex flex-column">
                                <h6 class="card-title">@product.Name</h6>
                                <p class="card-text fw-bold text-primary">@product.Price.ToString("C")</p>
                                <p class="card-text">@GetStarRating(product.Rating)</p>
                                @if (!product.InStock)
                                {
                                    <span class="badge bg-danger mb-2">Out of Stock</span>
                                }
                                <button class="btn btn-sm btn-success mt-auto"
                                        disabled="@(!product.InStock)"
                                        @onclick="() => { }" @onclick:stopPropagation="true">
                                    Add to Cart
                                </button>
                            </div>
                        </div>
                    </div>
                }
            </div>

            @* Pagination *@
            <nav class="mt-4" aria-label="Product pagination">
                <ul class="pagination justify-content-center">
                    <li class="page-item @(_currentPage <= 1 ? "disabled" : "")">
                        <button class="page-link" @onclick="() => GoToPage(_currentPage - 1)" disabled="@(_currentPage <= 1)">Previous</button>
                    </li>
                    @for (var i = 1; i <= _totalPages; i++)
                    {
                        var pageNum = i;
                        <li class="page-item @(pageNum == _currentPage ? "active" : "")">
                            <button class="page-link" @onclick="() => GoToPage(pageNum)">@pageNum</button>
                        </li>
                    }
                    <li class="page-item @(_currentPage >= _totalPages ? "disabled" : "")">
                        <button class="page-link" @onclick="() => GoToPage(_currentPage + 1)" disabled="@(_currentPage >= _totalPages)">Next</button>
                    </li>
                </ul>
            </nav>
        }
    </div>
</div>

@code {
    [Parameter] public EventCallback<int> OnProductSelected { get; set; }

    private const int PageSize = 12;

    private List<string>? _categories;
    private readonly HashSet<string> _selectedCategories = new();
    private decimal? _minPrice;
    private decimal? _maxPrice;
    private bool _inStockOnly;
    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private int _totalPages = 1;

    private PagedResult<Product>? _result;
    private bool _isLoading;
    private string? _error;

    private static readonly (string Value, string Label)[] _sortOptions =
    [
        ("price_asc", "Price: Low to High"),
        ("price_desc", "Price: High to Low"),
        ("name_asc", "Name: A-Z"),
        ("rating_desc", "Rating: Highest"),
    ];

    protected override async Task OnInitializedAsync()
    {
        try
        {
            _isLoading = true;
            _categories = await ProductService.GetCategoriesAsync();
            await LoadProducts();
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _isLoading = false;
        }
    }

    private async Task LoadProducts()
    {
        _isLoading = true;
        _error = null;
        StateHasChanged();

        try
        {
            var filter = new ProductFilter(
                Categories: _selectedCategories.Count > 0 ? _selectedCategories.ToList() : null,
                MinPrice: _minPrice,
                MaxPrice: _maxPrice,
                InStockOnly: _inStockOnly
            );

            _result = await ProductService.SearchAsync(filter, _sortBy, _currentPage, PageSize);
            _totalPages = Math.Max(1, (int)Math.Ceiling((double)_result.TotalCount / PageSize));
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _isLoading = false;
        }
    }

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            _selectedCategories.Add(category);
        else
            _selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        _currentPage = 1;
        await LoadProducts();
    }

    private async Task ClearFilters()
    {
        _selectedCategories.Clear();
        _minPrice = null;
        _maxPrice = null;
        _inStockOnly = false;
        _currentPage = 1;
        _sortBy = "price_asc";
        await LoadProducts();
    }

    private async Task OnSortChanged(ChangeEventArgs e)
    {
        _sortBy = e.Value?.ToString() ?? "price_asc";
        _currentPage = 1;
        await LoadProducts();
    }

    private async Task GoToPage(int page)
    {
        if (page < 1 || page > _totalPages) return;
        _currentPage = page;
        await LoadProducts();
    }

    private static string GetStarRating(double rating)
    {
        var rounded = (int)Math.Round(rating);
        return new string('★', rounded) + new string('☆', 5 - rounded);
    }
}

